import React from "react";

const Home = () => {
  return (
    <div className="page-container">
      <div className="form-card" style={{ width: "500px", textAlign: "center" }}>
        <h1 style={{ marginBottom: "20px" }}>
          Smart Expense Tracker
        </h1>

        <p
          style={{
            fontSize: "18px",
            color: "#666",
            lineHeight: "28px",
          }}
        >
          Track your income, expenses, analytics and
          monthly budget easily with a professional
          expense management system.
        </p>

        <div style={{ marginTop: "30px" }}>
          <a href="/login">
            <button
              style={{
                marginRight: "10px",
              }}
            >
              Login
            </button>
          </a>

          <a href="/register">
            <button>
              Register
            </button>
          </a>
        </div>
      </div>
    </div>
  );
};

export default Home;
